package com.nutrisense.entity;
import jakarta.persistence.*; import lombok.*; import java.time.*;
@Getter @Setter @Builder @NoArgsConstructor @AllArgsConstructor @Entity @Table(name="food_compatibility", uniqueConstraints=@UniqueConstraint(name="uk_food_disease", columnNames={"food_id","disease_id"})) public class FoodCompatibility { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @ManyToOne(fetch=FetchType.LAZY,optional=false) @JoinColumn(name="food_id",nullable=false) private Food food; @ManyToOne(fetch=FetchType.LAZY,optional=false) @JoinColumn(name="disease_id",nullable=false) private Disease disease; @Enumerated(EnumType.STRING) @Column(nullable=false,length=10) private Compatibility compatibility; @Lob @Column(columnDefinition="TEXT") private String reason; @Column(name="created_at",insertable=false,updatable=false) private Instant createdAt; public enum Compatibility { GREEN,YELLOW,RED } }
